from source import quicksort

def test_quicksort_preserves_duplicate_values():
    arr = [3, 1, 3, 2]
    result = quicksort(arr)
    assert len(result) == len(arr), (
        f"Expected length {len(arr)}, got {len(result)}: duplicates were dropped"
    )
    assert result == sorted(arr), (
        f"Expected {sorted(arr)}, got {result}"
    )
